def _utc_stamp() -> str:
    return datetime.now(timezone.utc).strftime("%Y%m%dT%H%M%SZ")


def _backup_once(root: Path, path: Path) -> str | None:
    if not path.exists():
        return None
    backup_dir = root / ".patch_backup" / PATCH_ID
    backup_dir.mkdir(parents=True, exist_ok=True)
    backup = backup_dir / (str(path.relative_to(root)).replace("/", "__").replace("\\", "__") + f".before_{PATCH_ID}")
    if not backup.exists():
        backup.write_text(path.read_text(encoding="utf-8", errors="replace"), encoding="utf-8")
    return str(backup)


def _write(root: Path, rel: str, text: str) -> dict[str, Any]:
    path = root / rel
    path.parent.mkdir(parents=True, exist_ok=True)
    existed = path.exists()
    backup = _backup_once(root, path) if existed else None
    current = path.read_text(encoding="utf-8", errors="replace") if existed else None
    mutated = current != text
    if mutated:
        path.write_text(text, encoding="utf-8")
    return {"path": rel, "existed_before": existed, "mutated": mutated, "backup_path": backup}


def _append_once(root: Path, rel: str, marker: str, block: str) -> dict[str, Any]:
    path = root / rel
    path.parent.mkdir(parents=True, exist_ok=True)
    existed = path.exists()
    text = path.read_text(encoding="utf-8", errors="replace") if existed else ""
    backup = _backup_once(root, path) if existed else None
    mutated = False
    if marker not in text:
        text = text.rstrip() + "\n" + block.lstrip()
        path.write_text(text, encoding="utf-8")
        mutated = True
    return {"path": rel, "existed_before": existed, "mutated": mutated, "backup_path": backup}


def _compile(path: Path) -> str | None:
    try:
        py_compile.compile(str(path), doraise=True)
    except Exception as exc:
        return f"{type(exc).__name__}: {exc}"
    return None


def apply_patch(project_root: Path) -> dict[str, Any]:
    root = project_root.resolve()
    mutations = []
    for rel, text in FILES.items():
        mutations.append(_write(root, rel, text))
    mutations.append(_append_once(root, "src/tradebot/production_hardening.py", "4B436661_H7 production_hardening runtime lock handle compatibility bridge", BRIDGE))
    mutations.append(_append_once(root, "tests/conftest.py", "4B436661_H7 pytest runtime lock handle import finalization", CONFTEST_BLOCK))
    compile_targets = [root / rel for rel in FILES if rel.endswith(".py")]
    compile_errors = {str(path.relative_to(root)): err for path in compile_targets if (err := _compile(path))}
    report: dict[str, Any] = {
        "patch_id": PATCH_ID,
        "patch_version": PATCH_VERSION,
        "patch_name": PATCH_NAME,
        "generated_at_utc": _utc_stamp(),
        "applied": True,
        "ok": not compile_errors,
        "phase_61_h7_source_mutation_performed": True,
        "runtime_lock_handle_export_fixed_by_patch": True,
        "production_hardening_final_import_compatibility_fixed_by_patch": True,
        "pytest_collection_runtime_lock_handle_finalizer_added_by_patch": True,
        "compile_errors": compile_errors,
        "py_compile_ok": not compile_errors,
        "mutation_results": mutations,
        "written_files": sorted(FILES.keys()),
        "missing_files": [],
    }
    report.update(SAFETY_FALSE_FLAGS)
    return report


def main() -> int:
    parser = argparse.ArgumentParser(description=PATCH_NAME)
    parser.add_argument("--project-root", default=".")
    parser.add_argument("--once-json", action="store_true")
    args = parser.parse_args()
    report = apply_patch(Path(args.project_root))
    print(json.dumps(report, sort_keys=True) if args.once_json else json.dumps(report, indent=2, sort_keys=True))
    return 0 if report["ok"] else 1


if __name__ == "__main__":
    raise SystemExit(main())
